var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"원정의 무사 귀환을 경하드립니다, 예하.","JPN":"遠征から無事に帰還なさったこと、心より喜ばしく思います、猊下。","ENG":"I am glad you made a safe return from your expedition, Your Eminence.","TWN":"恭喜主教從遠征平安歸來。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그래, 모두가 애써 준 덕분이다.","JPN":"ああ、皆が力を尽くしてくれたおかげだ。","ENG":"Yes. It is because everyone did their part.","TWN":"是的，多虧有大家的幫忙。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"신도들의 기도와 악단의 연주가 태양문을 밝혔기에 이번 원정이 성사될 수 있었던 것이지.","JPN":"信徒たちの祈りと楽団の演奏が太陽の扉を照らしたからこそ、この度の遠征が無事終わったのであろう。","ENG":"This expedition was made possible because our followers' prayers and the orchestra's performance illuminated the Solar Gates.","TWN":"是信徒們的祈禱和樂隊的演奏照亮了太陽門，才能順利完成這次遠征。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그런데…","JPN":"ところで……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하께선 돌아오시자마자, 데려온 아이의 이름을 성흔 순례단의 명단에 올리려 하셨더군요.","JPN":"猊下はお戻りの際、連れてきた子どもを聖痕の巡礼団に入れようとしたようですが。","ENG":"I noticed that, as soon as you returned, you attempted to register the child you brought for the Stigmata pilgrimage.","TWN":"主教剛回來不久就想讓您帶來的孩子加入聖痕朝聖團。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이번 원정에서 큰 공을 세운 아이다.","JPN":"この度の遠征で大きな手柄をたてた子どもだ。","ENG":"She has greatly contributed to this expedition.","TWN":"她在這次遠征立了大功。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그대들처럼 연주와 기도는 하지 않았으나, 목숨 걸고 나를 보좌하여 마왕에 맞섰지.","JPN":"そなたたちのように演奏や祈りを捧げたわけではないが、命を懸けて我とともに魔王に立ち向かった。","ENG":"Though she did not pray or perform like the others, she was my aid who fought against the Demon Lord with her life.","TWN":"她雖然沒有像你們演奏和祈禱，卻冒著生命危險輔佐我共同對抗魔王。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아이의 갸륵함을 인정하고자 하는 예하의 심정은 이해하나, 멋대로 태양문 바깥을 떠돌던 이교도에게 특혜를 주신다면 교단의 반발이 있을 것입니다.","JPN":"子どもの勇姿を称えたい猊下のお気持ちはわかります。しかし、太陽の扉の外で彷徨っていた異教徒に特別な恩恵を与えては、教団が反発すると思われます。","ENG":"I understand you wish to acknowledge the child's deeds. Yet, giving special treatment to a pagan who used to wander on the other side of the Solar Gates will trigger a revolt from the Order.","TWN":"我能理解您對孩子的讚賞和認可，但如果您對一個太陽門外的異教徒提供這樣的特殊待遇，恐怕會受到教團的反對。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그런가…","JPN":"そうか……","ENG":"Is that so...","TWN":"是嗎……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"물론 이교도라고는 하지만, 그 아이 역시 엘리시온의 일원.","JPN":"もちろん異教徒でもエリシオンの一員。","ENG":"Although she is a pagan... that child is also a part of Elysion.","TWN":"雖然是異教徒，但她也是艾利森的一員。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"마왕 토벌에 기여한 자를 예우하진 못할 망정 처벌을 내리는 건 과한 처사겠죠.","JPN":"魔王討伐の貢献を称えるどころか罰を与えるのは酷い仕打ちでしょう。","ENG":"It would be excessive to punish someone who has contributed to defeating the Demon Lord.","TWN":"懲罰一個為討伐魔王做出貢獻的人是不公平的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"역병에 감염되었을지도 모르니 저희가 건강만 살핀 뒤에 돌려보내겠습니다.","JPN":"疫病に感染している可能性もありますので、私たちが健康状態を確認してから送り返します。","ENG":"I shall check her health first and see if she is infected by the plague before sending her back.","TWN":"我們要檢查一下她的健康狀況，如果確定沒有被瘟疫傳染就會把她送回去。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"알겠다. 그대의 의견을 존중하도록 하지.","JPN":"わかった。そなたの意見を尊重しよう。","ENG":"Very well. I respect your decision.","TWN":"好吧，我尊重你的意見。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NAME_HIDE","text":{"KOREA":"추기경께서 직접 팔라딘을 위임하려 하시다니 별난 일이네요.","JPN":"枢機卿が直接パラディンへ委任するとは珍しいわね。","ENG":"Strange that the Cardinal is appointing a paladin herself.","TWN":"樞機主教竟然要親自委任聖騎士，真稀奇。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NAME_HIDE","text":{"KOREA":"늘 베풀기만 하시던 분께서 누군가를 갖고 싶어하는 모습을 보이실 줄이야.","JPN":"いつも自らが施すのみの方が誰かを必要とする姿を見せるとは。","ENG":"She was always so giving. I didn't expect to see her want someone like this.","TWN":"沒想到一向樂善好施的人也會想把一個人占為己有。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NAME_HIDE","text":{"KOREA":"이번 원정에서 어떤 심경의 변화라도 겪으신 걸까요?","JPN":"今回の遠征で何か心情の変化でもあったのかな？","ENG":"Do you think she had a change of heart during the expedition?","TWN":"難道在這次遠征中經歷了什麼心理變化嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"글쎄요, 카르멘.","JPN":"どうなんでしょうか、カルメン。","ENG":"Perhaps, Carmen.","TWN":"我也不清楚，卡門。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"제가 듣기엔, 예하의 목소리는 평소 그대로이셨습니다.","JPN":"私には猊下の声はいつもと変わらないように思えました。","ENG":"Her Eminence's voice was no different than before.","TWN":"主教的聲音和往常沒有兩樣。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"누구에게나 믿음과 온정을 베풀어 오신 분이기에, 이번에도 자신이 줄 수 있는 명예를 한 아이에게 베풀고 싶어하셨을 뿐이죠.","JPN":"誰にでも信頼と温情を示していた方ですから、今回も自分が与えられる名誉を一人の子どもに与えようとしただけです。","ENG":"She has always blessed others with faith and warmth. I believe she simply wanted to bless the child with honor.","TWN":"她對每個人都充滿信任和溫暖，這次也只是把自己能給予的榮譽分享給一個孩子而已吧。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"아…!","JPN":"あ……！","ENG":"Ah...!","TWN":"啊……！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"예하! 다녀오셨네요!","JPN":"猊下！　おかえりなさい！","ENG":"Your Eminence! You're back!","TWN":"主教！你回來了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"날 부르는 호칭이 바뀌었구나.","JPN":"我への呼び方が変わったな。","ENG":"You have changed the way you call me.","TWN":"你對我的稱呼變了呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"헤헤, 실은 제 또래의 어떤 여자애한테 혼났거든요.","JPN":"へへ、実は同い年の女の子に叱られました。","ENG":"Heh heh, in truth, I got scolded by some girl around my age.","TWN":"嘿嘿，我被一個年紀相仿的女孩子責駡了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"예하는 곧 성황이 될 고결하신 분이라 이름으로 부르는 건 엄청 무례한 거라고요.","JPN":"猊下はじきに聖皇になられる高潔な方だから、名前で呼ぶのはすごく無礼だって。","ENG":"I was told that it's considered impolite to say the noble name of someone about to become the pope.","TWN":"她說主教是一個即將成為聖皇的高尚之人，直呼你的名字是非常沒禮貌的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"제가 배운 게 많이 없어서 잘 몰랐어요. 앞으로는 조심할게요.","JPN":"私はそういうことよくわからなくて。これからは気を付けます。","ENG":"I didn't know better. I'll be careful from now on.","TWN":"都怪我才疏學淺，以後會注意的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…그리 신경 쓰지 않으니 걱정 말아라.","JPN":"……そう気にせんでもよい。思い煩うな。","ENG":"...It does not concern me, so do not worry.","TWN":"……我不會在意的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너는 나의 신도도 아니며, 섬길 의무 또한 없으니.","JPN":"そなたは我の信徒でもなければ、仕える義務もなかろう。","ENG":"You are not my follower, nor do you have a duty to serve me.","TWN":"你不是我的信徒，沒有侍奉我的義務。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그런데, 돌아가서 쉬지 않고 지금껏 날 기다리고 있던 것인가?","JPN":"ところで、今まで休まず我を待っていたのか？","ENG":"Have you been waiting for me all this time instead of going back and resting?","TWN":"不過你沒有回去休息，一直在等我嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"네!","JPN":"はいっ！","ENG":"Yes!","TWN":"是的！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"길고 험난한 원정이었다. 부상과 피로가 많이 쌓였을 터.","JPN":"長く激しい遠征であったのだ。負傷もあるし、疲労もたまっているだろう。","ENG":"It was a long and arduous expedition. You must be fatigued and injured.","TWN":"我們經歷了一段漫長而艱難的旅程。你身上一定累積了不少傷病和疲勞。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"피곤하지 않은 것이냐?","JPN":"疲れているのではないのか？","ENG":"Are you not exhausted?","TWN":"你不累嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"엄청 피곤해요!","JPN":"とても疲れています！","ENG":"I'm totally exhausted!","TWN":"我太累了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그치만 예하도 저랑 똑같이 싸우셨잖아요.","JPN":"でも、猊下も一緒に戦ったじゃないですか。","ENG":"But Your Eminence, you also fought with me.","TWN":"但主教也和我一起戰鬥了不是嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"저만 먼저 지쳐서 잠들어버리면 예하가 서운하실 테니까요.","JPN":"私が疲れて先に眠ってしまったら、猊下が寂しい気持ちになるでしょう。","ENG":"If I get tired and fall asleep first, then it would make you be sad.","TWN":"如果我先睡著了，主教豈不是會很難受。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가… 서운해한다고?","JPN":"我が……寂しい気持ちになるだと？","ENG":"I... would be sad?","TWN":"我會難受……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"제가 그랬거든요. 저 혼자 아프거나 피곤할 때, 정말로 많이 힘들었어요.","JPN":"私はそうでした。一人で苦しかったり、疲れている時は、とても辛かったのです。","ENG":"I was. It was really tough when I was sick or tired alone.","TWN":"我也有這樣的經歷。一個人生病或疲憊時，就感覺很難受。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그치만, 언니가 제 곁에 있을 땐 신기할 정도로 괜찮아지더라고요.","JPN":"でも、お姉さんが隣にいる時は、不思議と平気だったんです。","ENG":"But I was just fine when my sister was next to me. Strange, isn't it?","TWN":"但是只要姊姊在身邊，我的心情會很神奇地變好。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그래서 이번엔 제가 예하 곁에 있어드리려고요.","JPN":"だから今は私が、猊下のそばにいてあげようと思って。","ENG":"That's why I decided to be by your side this time, Your Eminence.","TWN":"所以這次我會陪在主教身邊。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…기특한 마음가짐이구나.","JPN":"……けなげな心持ちだな。","ENG":"...What a kind heart you have.","TWN":"……多麼善良的心啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"하지만 원정은 끝났다. 더는 모닥불을 피울 필요도, 함께 잠을 청할 이유도 없으니.","JPN":"しかし遠征はもう終わったのだ。これからは焚き火を起こすことも、ともに寝る必要もなかろう。","ENG":"But the expedition is over. There is no need to light a campfire or sleep together.","TWN":"但是遠征已經結束了。我們沒必要燃起營火，也沒必要一起睡覺。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너 또한 예전과 같은 삶으로 돌아가면 될 터.","JPN":"そなたも元の生活に戻ればよい。","ENG":"You could go back to your old life.","TWN":"你可以回到過去的生活當中了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그럼 저, 다시 밖으로 돌아가봐도 될까요? 언니를 아직 찾지 못했어요.","JPN":"では、私はまた外の世界に戻ってもいいんですか？　まだお姉さんを探し出せていません。","ENG":"Then... could I go back out there? I still haven't found my sister yet.","TWN":"那我可以回去外面嗎？我還沒找到我的姊姊。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네가 건강하지 못하면 가족도 걱정할 것이다.","JPN":"だが、そなたが健康でなければ、家族は心配するであろう。","ENG":"Your family will worry if you are not healthy.","TWN":"如果你身體不健康，你的家人也會擔心。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"신전의 형제자매들에게 바깥에 남겨진 생존자를 찾도록 일러두었으니, 너는 부상을 치료받으며 쉬어라.","JPN":"神殿にいる兄弟姉妹に外の生存者を探すよう命じた。そなたは傷の治療を受け休むように。","ENG":"I have ordered the brothers and sisters of this temple to find any survivors outside, so you should rest and treat your wounds.","TWN":"我已經指示聖殿裡的兄弟姐們去搜尋外面的倖存者了。你就安心養傷吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"으음… 예하께서 그렇게까지 말씀하신다면, 알겠어요.","JPN":"んん……猊下がそう言うなら、わかりました。","ENG":"Hmm... If you say so, Your Eminence.","TWN":"嗯……既然主教這麼說，那我明白了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너무 걱정 마라. 날이 밝으면 나도 함께 동행할 테니.","JPN":"そう案ずるな。夜が明けたら我もともに行くとしよう。","ENG":"Do not worry so much. When dawn breaks, I shall accompany you.","TWN":"別擔心，太陽升起後，我也會與你同行。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"정말요?! 감사합니다, 에클레…!","JPN":"本当ですか！？　ありがとうございます、エクレ……！","ENG":"Really?! Thank you, Miss Ecc–!","TWN":"真的嗎？！謝謝你，艾可露……！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"아 아니, 예하!","JPN":"い、いや、猊下！","ENG":"Oh, I mean, Your Eminence!","TWN":"不，主教！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"꽃 말씀이신가요?","JPN":"お花ですか？","ENG":"A flower?","TWN":"花？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 아이의 언니가 흰 서리꽃이란 걸 찾고 있었다더군.","JPN":"その子どもの姉が白い雪の花を探していたようなのだ。","ENG":"That child's sister went out in search of something called the white frost flower.","TWN":"她姊姊在找一種叫白霜花的東西。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"약을 연구하는 그대라면 아는 게 있을 것이라 생각했다.","JPN":"薬を研究しているそなたなら、なにか知っているのではないか。","ENG":"Since you are knowledgeable about medicine, I thought you would know something about it.","TWN":"我想起你經常研究藥草，所以就來請教你。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음.","JPN":"ふむ。","ENG":"Hmm.","TWN":"嗯嗯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우선 흰 서리꽃은 병을 치료하는 용도가 아니에요. 오히려 독으로 쓰이죠.","JPN":"まず、白い雪の花は薬草ではありません。むしろ毒として使われています。","ENG":"First of all, the white frost flower is not used for treating illnesses. It is used for poison.","TWN":"白霜花並不是治病的藥草，而是一種毒藥。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"사람을 죽이는 독은 아니지만, 성흔을 가진 자들의 힘을 끊어버리는 성분이 있거든요.","JPN":"人を殺す毒ではないけど、聖痕を持っている人の力を断ち切る成分があります。","ENG":"It does not kill people, but it has a property that can break the power of those who have the Stigmata.","TWN":"它雖然不致命，但是會毀掉擁有聖痕之人的力量。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"물론 거기에 들어가는 재료가 꽃이 전부는 아니지만요.","JPN":"もちろん、毒の材料はその花だけではないのですが。","ENG":"But of course, the flower is not the sole ingredient to this concoction.","TWN":"當然，那朵花並不是這種毒藥唯一的藥材。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…독이라고?","JPN":"……毒だと？","ENG":"...Poison?","TWN":"……毒藥？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"솔직히 말씀드리면, 그건 이교도인들이 취급하는 약이예요.","JPN":"正直に言いますと、それは異教徒が使う薬です。","ENG":"In truth, it is medicine that pagans use.","TWN":"其實這是異教徒使用的藥。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 사람들은 성흔을 축복이 아닌 저주로 여겨 없애고 싶어 하는 거죠.","JPN":"彼らは聖痕を祝福ではなく、呪いだと思っているから消したがるのです。","ENG":"They want to erase the Stigmata because they see it as a curse rather than a blessing.","TWN":"因為他們認為聖痕是一種詛咒而不是祝福，所以才會想要毀掉它。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"저주라고? 그들은 어째서 성흔을 거부하는 것이지?","JPN":"呪いだと？　彼らはなぜ聖痕を拒むのだ？","ENG":"A curse, you say? Why would they refuse the Stigmata?","TWN":"詛咒？他們為何會排斥聖痕？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"교단은 성흔에 멸망을 피하는 답이 있다고 판단했어요.","JPN":"教団は聖痕に滅亡を回避するための答えがあると判断したのです。","ENG":"The Order has determined that the Stigmata is the answer to avoiding devastation.","TWN":"教團認為免於末日的答案就在聖痕之中。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래서 성흔을 가진 신도들을 선별해 그 답에 다가가기 위한 길을 찾고 있죠.","JPN":"そのため聖痕を持っている信徒を選別して、その答えに近づくための道を探しています。","ENG":"That is why they are selecting followers with the Stigmata to find a path to reach that answer.","TWN":"所以才會選出擁有聖痕的信徒一起探索著最終的答案。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이교도인들은 그런 저희가 성과를 이루는 걸 원치 않는 거예요.","JPN":"異教徒は私たちに成果を上げてほしくないんです。","ENG":"And pagans do not want us to achieve our goal.","TWN":"而異教徒不希望我們在這條道路上取得成就。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그렇게 선별된 신도들은 어떻게 되지?","JPN":"なら、選別された信徒はどうなる？","ENG":"Then what happens to those selected followers?","TWN":"那些被選中的信徒會怎樣？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"예하께서도 이미 짐작하시지 않았나요?","JPN":"それは猊下もご存知のはずです。","ENG":"Don't you already know, Your Eminence?","TWN":"主教不是已經猜到了嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리에게 남은 시간은 그리 많지 않고, 희생 없이 이뤄지는 구원은 없다는 걸.","JPN":"私たちに残された時間はそう多くありません。犠牲なくして救いが得られることはないということです。","ENG":"We do not have much time, and salvation cannot be achieved without sacrifice.","TWN":"我們所剩的時間不多了，沒有犧牲就不能實現救贖。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네퀴티아는 어디에 있나? 그녀를 만나야겠다.","JPN":"ネキティアはどこだ？　今から彼女に会う。","ENG":"Where is Nequitia? I need to see her.","TWN":"莉奎蒂亞在哪裡？我要去見她。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"달콤하지 않은 진실을 함부로 떠벌린 저의 무례를 부디 용서하세요, 예하.","JPN":"辛い真実をありのまま打ち明けてしまった私の無礼を、どうかお許しください、猊下。","ENG":"Forgive my tactless approach to this disturbing subject matter, Your Eminence.","TWN":"我說了一些殘酷的真相，還主教見諒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 이것만은 알아주시길.","JPN":"でも、これだけはわかってほしいのです。","ENG":"But please know this.","TWN":"但希望主教明白一件事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지금도 역병에 죽어나가고 있는 엘리시온의 만민이 예하께서 가져다주실 구원만을 기다리고 있단 걸요.","JPN":"今も疫病で死んでいくエリシオンの人々は猊下がもたらしてくださる救いだけを待ち望んでいるということを。","ENG":"The people of Elysion dying from the plague are only waiting for the salvation that you will bring, Your Eminence.","TWN":"即使是現在這一刻，艾利森的人們仍然忍受著瘟疫的侵襲，苦苦等待著主教的救贖。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"악취가 짙어지는구나.","JPN":"悪臭が濃くなっている。","ENG":"The foul stench grows thicker.","TWN":"臭味越來越濃。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"제때 당도하지 못하면, 이 세계도 우리와 같은 전철을 밟게 될 터…","JPN":"もし間に合わねば、この世界も我らの世界と同じ道を歩むことになるであろう……","ENG":"If I do not arrive in time, this world will follow the same path to destruction as mine...","TWN":"如果我們不能及時趕到，這個世界也只能重蹈覆轍……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…나와 같이 떠도는 검은 짐승들아.","JPN":"……我とともに彷徨っている黒き獣たちよ。","ENG":"...O, dark beasts who wander as I do.","TWN":"……和我一樣四處遊蕩的黑色野獸們。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너희는 잠든 그녀가 깨어나 이곳을 너희의 탁한 색채로 물들이길 원하는구나.","JPN":"そなたたちは彼女が目覚め、この場所をそなたたちと同じ淀んだ黒色に染めあげることを望んでいるのだな。","ENG":"You wish for her to awaken from her slumber and taint this place with the same gloomy hue as your own.","TWN":"你們希望她從沉睡中醒來，用你們那渾濁的色彩來漬染這個地方。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나 이 세계의 운명을 택하는 건 너희의 몫도… 그녀의 몫이 되어서도 안된다.","JPN":"だが、この世界の運命を選ぶのはそなたたちでも……彼女でもない。","ENG":"Yet, this world's fate must not lie in your hands... nor hers.","TWN":"但能夠選擇這個世界的命運的不應該是你們……也不應該是她……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그러니, 비켜라.","JPN":"だから、退け。","ENG":"So, be gone!","TWN":"所以給我讓開。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};